import React, { useState, useEffect } from 'react';
import { Boleto, fetchBoletosByCustomerId, marcarBoletoComoPago, gerarPixParaBoleto, gerarCarne } from '../../api/billing';

interface BillingTabProps {
    customerId: string;
}

export const BillingTab: React.FC<BillingTabProps> = ({ customerId }) => {
    const [boletos, setBoletos] = useState<Boleto[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [pixQrCode, setPixQrCode] = useState<string | null>(null);

    const loadBoletos = async () => {
        setLoading(true);
        setError(null);
        try {
            const data = await fetchBoletosByCustomerId(customerId);
            setBoletos(data);
        } catch (err) {
            setError('Falha ao carregar boletos.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadBoletos();
    }, [customerId]);

    const handleMarcarPago = async (boletoId: string) => {
        await marcarBoletoComoPago(boletoId);
        loadBoletos();
    };

    const handleGerarPix = async (boletoId: string) => {
        const { qrCode } = await gerarPixParaBoleto(boletoId);
        setPixQrCode(qrCode);
        loadBoletos();
    };

    const handleGerarCarne = async (numParcelas: 6 | 12) => {
        await gerarCarne(customerId, numParcelas);
        loadBoletos();
    };

    if (loading) return <p>Carregando boletos...</p>;
    if (error) return <p style={{ color: '#b91c1c' }}>{error}</p>;

    return (
        <div>
            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
                <button onClick={() => handleGerarCarne(6)}>Gerar Carnê (6 meses)</button>
                <button onClick={() => handleGerarCarne(12)}>Gerar Carnê (12 meses)</button>
            </div>
            {pixQrCode && (
                <div style={{ marginBottom: '1rem', padding: '1rem', border: '1px solid #e2e8f0', borderRadius: 8 }}>
                    <h4>PIX QR Code Gerado</h4>
                    <p>Aponte a câmera do seu celular para o código abaixo:</p>
                    <pre style={{ background: '#f1f5f9', padding: '0.5rem', borderRadius: 4 }}>{pixQrCode}</pre>
                    <button onClick={() => setPixQrCode(null)}>Fechar</button>
                </div>
            )}
            <table>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Valor</th>
                        <th>Vencimento</th>
                        <th>Status</th>
                        <th>Ações</th>
                    </tr>
                </thead>
                <tbody>
                    {boletos.map(boleto => (
                        <tr key={boleto.id}>
                            <td>{boleto.id}</td>
                            <td>R$ {boleto.amount.toFixed(2)}</td>
                            <td>{boleto.dueDate}</td>
                            <td>{boleto.status}</td>
                            <td>
                                <div style={{ display: 'flex', gap: '0.4rem' }}>
                                    {boleto.status === 'Pendente' && <button onClick={() => handleMarcarPago(boleto.id)}>Baixa Manual</button>}
                                    {boleto.status !== 'Pago' && <button onClick={() => handleGerarPix(boleto.id)}>Criar PIX</button>}
                                    <button>Enviar por Email</button>
                                </div>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};
